1093	
1094	    auto parser = build_chat_peg_parser([&](common_chat_peg_builder & p) {
1095	        // Functionary v3.2 format:
1096	        // - Normal content: >>>all\n{content}
1097	        // - Tool calls: >>>function_name\n{json_args}
1098	        // Generation prompt ends with ">>>" so model outputs recipient immediately
1099	
1100	        // Build content parser for >>>all\n{content}
1101	        // When tools are present, content stops before the next ">>>" (tool call)
1102	        // When no tools, content goes until end
1103	        auto content_until_tool = p.literal("all\n") + p.content(p.until(">>>"));
1104	        auto content_until_end  = p.literal("all\n") + p.content(p.rest());
1105	        auto generation_prompt  = p.literal(inputs.generation_prompt);
1106	
1107	        // If no tools or tool_choice is NONE, just parse content
1108	        if (!has_tools || inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_NONE) {
1109	            // When no tools, just match the prefix and capture everything after
1110	            return generation_prompt + content_until_end + p.end();
1111	        }
1112	
1113	        // Build tool call parsers for each available function
1114	        auto tool_choice = p.choice();
1115	        foreach_function(inputs.tools, [&](const json & tool) {
1116	            const auto & function = tool.at("function");
1117	            std::string  name     = function.at("name");
1118	            const auto & schema   = function.at("parameters");
1119	
1120	            // Tool format: >>>function_name\n{json_args}
1121	            auto tool_parser = p.tool(
1122	                p.tool_open(p.tool_name(p.literal(name)) + p.literal("\n")) +
1123	                p.tool_args(p.schema(p.json(), "tool-" + name + "-schema", schema))
1124	            );
1125	
1126	            tool_choice |= p.rule("tool-" + name, tool_parser);
1127	        });
1128	
1129	        auto content_only = content_until_end;
1130	        auto tools_only = p.trigger_rule("tools", p.one_or_more(tool_choice));
1131	        auto content_and_tools = content_until_tool + tools_only;
1132	
1133	        auto ret = p.eps();
1134	        if (inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_REQUIRED) {
1135	            if (inputs.parallel_tool_calls) {
1136	                ret = p.choice({ content_and_tools, tools_only }) + p.end();
1137	            } else {
1138	                ret = p.choice({ content_until_tool + tool_choice, tools_only }) + p.end();
1139	            }
1140	        } else if (inputs.parallel_tool_calls) {
1141	            ret = p.choice({ content_and_tools, content_only, tools_only }) + p.end();
1142	        } else {
1143	            auto content_and_tool = content_until_tool + tool_choice;
1144	            ret = p.choice({ content_and_tool, content_only, tool_choice }) + p.end();
1145	        }
1146	        return generation_prompt + ret;
1147	    });
1148	
1149	    data.parser = parser.save();
1150	
1151	    if (include_grammar) {
1152	        data.grammar_lazy = inputs.tool_choice == COMMON_CHAT_TOOL_CHOICE_AUTO;
1153	
1154	        data.grammar = build_grammar([&](const common_grammar_builder & builder) {
1155	            foreach_function(inputs.tools, [&](const json & tool) {
1156	                const auto & function = tool.at("function");
1157	                auto         schema   = function.at("parameters");
1158	                builder.resolve_refs(schema);
1159	            });
1160	            parser.build_grammar(builder, data.grammar_lazy);
1161	        });
