1520	
1521	static void map_developer_role_to_system(json & messages) {
1522	    for (auto & message : messages) {
1523	        if (message.contains("role")) {
1524	            if (message["role"] == "developer") {
1525	                message["role"] = "system";
1526	            }
1527	        }
1528	    }
1529	}
