1532	// if first message is system and template does not support it, merge it with next message
1533	static void system_message_not_supported(json & messages) {
1534	    if (!messages.empty() && messages.front().at("role") == "system") {
1535	        if (messages.size() > 1) {
1536	            LOG_DBG("Merging system prompt into next message\n");
1537	            auto & first_msg = messages.front();
1538	            auto & second_msg = messages[1];
1539	            second_msg["content"] = first_msg.at("content").get<std::string>()
1540	                + "\n" + second_msg.at("content").get<std::string>();
1541	            messages.erase(messages.begin());
1542	        } else {
1543	            LOG_WRN("Removing system prompt due to template not supporting system role\n");
1544	            messages.erase(messages.begin());
